4673   auto VecTCScev = SE.getMulExpr(SE.getUDivExpr(TCScev, VFxUF), VFxUF);
4674   if (auto *ConstVecTC = dyn_cast<SCEVConstant>(VecTCScev))
4675     Plan.getVectorTripCount().setUnderlyingValue(ConstVecTC->getValue());
