4208   LLVM_DEBUG(dbgs() << "LV: Scalar loop costs: " << ExpectedCost << ".\n");
4209   assert(ExpectedCost.isValid() && "Unexpected invalid cost for scalar loop");
4210   assert(
4211       any_of(VPlans,
4212              [](std::unique_ptr<VPlan> &P) { return P->hasScalarVFOnly(); }) &&
4213       "Expected Scalar VF to be a candidate");
4214 
4215   const VectorizationFactor ScalarCost(ElementCount::getFixed(1), ExpectedCost,
4216                                        ExpectedCost);
4217   VectorizationFactor ChosenFactor = ScalarCost;
4218 
4219   bool ForceVectorization = Hints.getForce() == LoopVectorizeHints::FK_Enabled;
4220   if (ForceVectorization &&
4221       (VPlans.size() > 1 || !VPlans[0]->hasScalarVFOnly())) {
4222     // Ignore scalar width, because the user explicitly wants vectorization.
4223     // Initialize cost to max so that VF = 2 is, at least, chosen during cost
4224     // evaluation.
4225     ChosenFactor.Cost = InstructionCost::getMax();
4226   }
4227 
4228   for (auto &P : VPlans) {
4229     ArrayRef<ElementCount> VFs(P->vectorFactors().begin(),
4230                                P->vectorFactors().end());
4231 
4232     SmallVector<VPRegisterUsage, 8> RUs;
4233     if (any_of(VFs, [this](ElementCount VF) {
4234           return CM.shouldConsiderRegPressureForVF(VF);
4235         }))
4236       RUs = calculateRegisterUsageForPlan(*P, VFs, TTI, CM.ValuesToIgnore);
4237 
4238     for (unsigned I = 0; I < VFs.size(); I++) {
4239       ElementCount VF = VFs[I];
4240       // The cost for scalar VF=1 is already calculated, so ignore it.
4241       if (VF.isScalar())
4242         continue;
4243 
4244       /// If the register pressure needs to be considered for VF,
4245       /// don't consider the VF as valid if it exceeds the number
4246       /// of registers for the target.
4247       if (CM.shouldConsiderRegPressureForVF(VF) &&
4248           RUs[I].exceedsMaxNumRegs(TTI, ForceTargetNumVectorRegs))
4249         continue;
4250 
4251       InstructionCost C = CM.expectedCost(VF);
4252 
4253       // Add on other costs that are modelled in VPlan, but not in the legacy
4254       // cost model.
4255       VPCostContext CostCtx(CM.TTI, *CM.TLI, *P, CM, CM.CostKind, CM.PSE,
4256                             OrigLoop);
4257       VPRegionBlock *VectorRegion = P->getVectorLoopRegion();
4258       assert(VectorRegion && "Expected to have a vector region!");
4259       for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
4260                vp_depth_first_shallow(VectorRegion->getEntry()))) {
4261         for (VPRecipeBase &R : *VPBB) {
4262           auto *VPI = dyn_cast<VPInstruction>(&R);
4263           if (!VPI)
4264             continue;
4265           switch (VPI->getOpcode()) {
4266           // Selects are only modelled in the legacy cost model for safe
4267           // divisors.
4268           case Instruction::Select: {
4269             if (auto *WR =
4270                     dyn_cast_or_null<VPWidenRecipe>(VPI->getSingleUser())) {
4271               switch (WR->getOpcode()) {
4272               case Instruction::UDiv:
4273               case Instruction::SDiv:
4274               case Instruction::URem:
4275               case Instruction::SRem:
4276                 continue;
4277               default:
4278                 break;
4279               }
4280             }
4281             C += VPI->cost(VF, CostCtx);
4282             break;
4283           }
4284           case VPInstruction::ActiveLaneMask: {
4285             unsigned Multiplier =
4286                 cast<VPConstantInt>(VPI->getOperand(2))->getZExtValue();
4287             C += VPI->cost(VF * Multiplier, CostCtx);
4288             break;
4289           }
4290           case VPInstruction::ExplicitVectorLength:
4291             C += VPI->cost(VF, CostCtx);
4292             break;
4293           default:
4294             break;
4295           }
4296         }
4297       }
4298 
4299       VectorizationFactor Candidate(VF, C, ScalarCost.ScalarCost);
4300       unsigned Width =
4301           estimateElementCount(Candidate.Width, CM.getVScaleForTuning());
4302       LLVM_DEBUG(dbgs() << "LV: Vector loop of width " << VF
4303                         << " costs: " << (Candidate.Cost / Width));
4304       if (VF.isScalable())
4305         LLVM_DEBUG(dbgs() << " (assuming a minimum vscale of "
4306                           << CM.getVScaleForTuning().value_or(1) << ")");
4307       LLVM_DEBUG(dbgs() << ".\n");
4308 
4309       if (!ForceVectorization && !willGenerateVectors(*P, VF, TTI)) {
4310         LLVM_DEBUG(
4311             dbgs()
4312             << "LV: Not considering vector loop of width " << VF
4313             << " because it will not generate any vector instructions.\n");
4314         continue;
4315       }
4316 
4317       if (CM.OptForSize && !ForceVectorization && hasReplicatorRegion(*P)) {
4318         LLVM_DEBUG(
4319             dbgs()
4320             << "LV: Not considering vector loop of width " << VF
